#include <stdio.h>
#include <string.h>

#define MAX_S 8
#define MAX_W 2
#define MAX_T 64

int dp[MAX_S + 1][1 << 3];

int main() {
    int T, S, W1, W2, W3, i, j, k, ans;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %d %d", &S, &W1, &W2, &W3);
        memset(dp, 0x3f, sizeof(dp));
        dp[0][0] = 0;
        for (i = 0; i <= S; i++) {
            for (j = 0; j < (1 << 3); j++) {
                for (k = 0; k < 3; k++) {
                    if ((j >> k) & 1) {
                        if (i + W1 + W2 + W3 <= S) {
                            dp[i + W1 + W2 + W3][j ^ (1 << k)] = dp[i][j] + 1;
                        } else {
                            dp[S][j ^ (1 << k)] = dp[i][j] + 1;
                        }
                    }
                }
            }
        }
        ans = dp[S][(1 << 3) - 1];
        for (i = 0; i <= S; i++) {
            for (j = 0; j < (1 << 3); j++) {
                if (dp[i][j] < ans) {
                    ans = dp[i][j];
                }
            }
        }
        printf("%d\n", ans);
    }
    return 0;
}

